CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_discovery_run_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  session_app_user_id uuid;
begin
  if new.session_id is not null then
    select s.app_user_id
    into session_app_user_id
    from public.app_sessions s
    where s.id = new.session_id;

    if session_app_user_id is null then
      raise exception 'discovery_runs.session_id is invalid';
    end if;

    if new.app_user_id <> session_app_user_id then
      raise exception 'discovery_runs.app_user_id must match app_sessions.app_user_id';
    end if;
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_event_session_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  session_app_user_id uuid;
begin
  if new.session_id is not null then
    select s.app_user_id
    into session_app_user_id
    from public.app_sessions s
    where s.id = new.session_id;

    if session_app_user_id is null then
      raise exception 'app_events.session_id is invalid';
    end if;

    if new.app_user_id is null then
      new.app_user_id := session_app_user_id;
    elsif new.app_user_id <> session_app_user_id then
      raise exception 'app_events.app_user_id must match app_sessions.app_user_id';
    end if;
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_place_photo_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  active_count integer;
begin
  if new.is_cover and new.status <> 'active' then
    raise exception 'cover photo must be active';
  end if;

  if new.status = 'active' and new.provider_id is null then
    raise exception 'active photo must have a provider';
  end if;

  if new.status = 'active' then
    select count(*)
    into active_count
    from public.place_photos ph
    where ph.place_id = new.place_id
      and ph.status = 'active'
      and ph.id <> coalesce(new.id, '00000000-0000-0000-0000-000000000000'::uuid);

    if active_count >= 5 then
      raise exception 'a place can have at most 5 active photos';
    end if;
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_place_tag_membership()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if public.require_tag_group(new.tag_id, 'place_type') then
    raise exception 'place_type tags belong in places.place_type_tag_id, not place_tags';
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_place_type_tag()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if new.place_type_tag_id is null then
    raise exception 'places.place_type_tag_id is required';
  end if;

  if not public.require_tag_group(new.place_type_tag_id, 'place_type') then
    raise exception 'places.place_type_tag_id must reference a place_type tag';
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_route_place_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if not exists (
    select 1
    from public.places p
    where p.id = new.place_id
      and p.app_status in ('ready', 'published')
  ) then
    raise exception 'route place must reference a ready or published place';
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_saved_route_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  place_count integer;
begin
  if new.status = 'saved' then
    if new.title is null or btrim(new.title) = '' then
      raise exception 'saved route title is required';
    end if;

    select count(*)
    into place_count
    from public.route_places rp
    where rp.route_id = new.id;

    if place_count < 2 then
      raise exception 'saved route must have at least 2 places';
    end if;
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.validate_shared_link_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if new.content_type = 'place' then
    if not exists (
      select 1
      from public.places p
      where p.id = new.place_id
        and p.app_status = 'published'
    ) then
      raise exception 'place share link must reference a published place';
    end if;
  elsif new.content_type = 'route' then
    if not exists (
      select 1
      from public.routes r
      where r.id = new.route_id
        and r.status = 'saved'
        and r.is_public = true
    ) then
      raise exception 'route share link must reference a public saved route';
    end if;
  end if;

  return new;
end;
$function$
